# Module defining shape classes with inheritance and interface implementation
from types_module import Color, IDrawable, IMeasurable, Point

# Base shape class
class Shape(IDrawable):
    color: Color
    position: Point

    def __init__(self, color: Color, position: Point):
        self.color = color
        self.position = position

    @virtual
    def draw(self) -> str:
        return "Drawing shape"

# Rectangle class with inheritance and interface implementation
class Rectangle(Shape, IMeasurable):
    width: float
    height: float

    def __init__(self, color: Color, position: Point, width: float, height: float):
        super().__init__(color, position)
        self.width = width
        self.height = height

    @override
    def draw(self) -> str:
        return "Drawing rectangle"

    @override
    def area(self) -> float:
        return self.width * self.height

# Circle class with inheritance and interface implementation
class Circle(Shape, IMeasurable):
    radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self.radius = radius

    @override
    def draw(self) -> str:
        return "Drawing circle"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

