# Utility module for shape operations
from types_module import IMeasurable, Color
from shapes_module import Shape

# Calculate total area of measurable shapes
def total_area(shapes: list[IMeasurable]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

# Get color name from enum
def color_name(color: Color) -> str:
    return color.name

# Shape renderer class for managing shape collections
class ShapeRenderer:
    shapes: list[Shape]

    def __init__(self):
        self.shapes = []

    def add_shape(self, shape: Shape) -> None:
        self.shapes.append(shape)

    def render_all(self) -> list[str]:
        results: list[str] = []
        for shape in self.shapes:
            results.append(shape.draw())
        return results

    def count(self) -> int:
        return len(self.shapes)
